NB: This method currently combines error handling, state updating, and operations on the CM handle within a single function. Splitting some parts into helper methods could improve readability.



processModuleSyncFailure(yangModelCmHandle, compositeState, inUpgrade, e);

 private void processModuleSyncFailure(final YangModelCmHandle yangModelCmHandle, 
                                       final CompositeState compositeState, 
                                       final boolean inUpgrade, 
                                       final Exception e) {
        log.warn("Failed to process module {}: {}", yangModelCmHandle.getId(), e.getMessage());
        LockReasonCategory lockReasonCategory = inUpgrade ? LockReasonCategory.MODULE_UPGRADE_FAILED : LockReasonCategory.MODULE_SYNC_FAILED;

        moduleOperationsUtils.updateLockReasonWithAttempts(compositeState, lockReasonCategory, e.getMessage());
        setCmHandleStateLocked(yangModelCmHandle, compositeState.getLockReason());
    }
